android.extraProguardRules:
-keep class com.facebook.react.** { *; }
-keep class com.facebook.hermes.** { *; }
-keep class com.facebook.jni.** { *; }
-keep class com.swmansion.reanimated.** { *; }
-keep class com.mrousavy.camera.** { *; }
-keep class com.mrousavy.worklets.** { *; }
-keep class com.reactnativeworklets.** { *; }
-keep class com.visioncameraresizeplugin.** { *; }
-keep class com.google.android.gms.ads.** { *; }
-keep class com.reactnativegooglemobileads.** { *; }
-keep class expo.modules.** { *; }
-keep class com.swmansion.gesturehandler.** { *; }
-keep class com.th3rdwave.safeareacontext.** { *; }
-keep class com.swmansion.rnscreens.** { *; }
-keep class com.horcrux.svg.** { *; }
-keep class com.reactnativecommunity.asyncstorage.** { *; }
-keep class kotlin.** { *; }
-keepattributes Signature, *Annotation*, EnclosingMethod, InnerClasses
-keep class * extends com.facebook.react.bridge.JavaScriptModule { *; }
-keep class * extends com.facebook.react.bridge.NativeModule { *; }
-keepclassmembers class * { @com.facebook.react.uimanager.annotations.ReactProp <methods>; }
-keepclassmembers class * { @com.facebook.react.uimanager.annotations.ReactPropGroup <methods>; }
-keepclassmembers class * extends com.facebook.react.uimanager.ViewManager { <init>(...); }
